import { create } from "zustand";
import { persist, createJSONStorage } from "zustand/middleware";

export type NeedReceiptStore = {
  receiptStatus: string;
  setStatus: (receipt: string) => void;
};

export type UserDataStore = {
  firstName: string;
  lastName: string;
  contactNum: number;
  newData: {};
  setFirstName: (by: string) => void;
  setLastName: (by: string) => void;
  setcontactNum: (by: number) => void;
  saveData: (data: {}) => void;
};

// store the user's data receipt
export const useNeedReceiptStore = create<NeedReceiptStore>()(
  persist(
    (set, get) => ({
      receiptStatus: "",
      setStatus: (receipt: string) =>
        set({ receiptStatus: (get().receiptStatus = receipt) }),
    }),
    {
      name: "receipt-storage",
      storage: createJSONStorage(() => sessionStorage),
    }
  )
);

export const useUserDataStore = create<UserDataStore>()(
  persist(
    (set, get) => ({
      firstName: "",
      lastName: "",
      contactNum: 0,
      newData: {},
      setFirstName: (by) => set({ firstName: (get().firstName = by) }),
      setLastName: (by) => set({ firstName: (get().lastName = by) }),
      setcontactNum: (by) => set({ contactNum: (get().contactNum = by) }),
      saveData: (data: {}) => set({ newData: (get().newData = data) }),
    }),
    {
      name: "user-data-storage",
      storage: createJSONStorage(() => sessionStorage),
    }
  )
);
